// n8n Code Node: Rule-Based Lead Qualification - Free
// Purpose: Score cleaning service leads as Hot, Warm, Cold, or Needs Manual Review

const lead = $input.first().json;

function clean(value) {
  return String(value || '').trim();
}

const fullName = clean(lead.full_name);
const firstName = fullName ? fullName.split(/\s+/)[0] : 'there';
const email = clean(lead.email);
const phone = clean(lead.phone);
const service = clean(lead.service_needed);
const propertyType = clean(lead.property_type);
const location = clean(lead.location);
const schedule = clean(lead.preferred_schedule);
const budget = clean(lead.budget_range);
const urgency = clean(lead.urgency);
const source = clean(lead.source);
const notes = clean(lead.extra_notes);

const missingFields = [];

for (const field of ['full_name', 'email', 'phone', 'service_needed']) {
  if (!clean(lead[field])) {
    missingFields.push(field);
  }
}

const combined = `${service} ${propertyType} ${location} ${schedule} ${budget} ${notes}`.toLowerCase();
const selectedUrgency = urgency.toLowerCase();

const urgentWords = [
  'urgent',
  'asap',
  'today',
  'tomorrow',
  'this weekend',
  'weekend',
  'same day',
  'move-out',
  'move out',
  'move-in',
  'move in',
  'end of lease',
  'inspection',
  'handover',
  'turnover',
  'before guest',
  'before arrival',
  'before moving',
  'immediately'
];

const warmWords = [
  'next week',
  'quote',
  'estimate',
  'pricing',
  'interested',
  'available',
  'schedule',
  'monthly',
  'weekly',
  'regular',
  'looking for',
  'can you help'
];

const coldWords = [
  'just checking',
  'just browsing',
  'maybe',
  'later',
  'not sure',
  'not ready',
  'cheap',
  'cheapest',
  'lowest',
  'free',
  'no budget',
  'no budget yet',
  'next month',
  'someday',
  'only asking',
  'for future reference'
];

const clearServiceWords = [
  'deep',
  'move',
  'move-out',
  'move out',
  'move-in',
  'move in',
  'office',
  'weekly',
  'one-time',
  'one time',
  'regular',
  'post-construction',
  'construction',
  'airbnb',
  'rental',
  'apartment',
  'house',
  'condo'
];

const hasUrgentIntent = urgentWords.some(word => combined.includes(word));
const hasWarmIntent = warmWords.some(word => combined.includes(word));
const hasColdIntent = coldWords.some(word => combined.includes(word));
const hasClearService = clearServiceWords.some(word => combined.includes(word));

const hasCompleteContact = Boolean(fullName && email && phone);
const hasBasicLeadDetails = Boolean(service && location);
const hasScheduleAndBudget = Boolean(schedule && budget);
const hasStrongLeadInfo = Boolean(hasCompleteContact && hasBasicLeadDetails && hasScheduleAndBudget);

let scorePoints = 0;

if (fullName) scorePoints += 1;
if (email) scorePoints += 1;
if (phone) scorePoints += 1;
if (service) scorePoints += 2;
if (location) scorePoints += 1;
if (schedule) scorePoints += 1;
if (budget) scorePoints += 1;
if (hasUrgentIntent) scorePoints += 3;
if (hasWarmIntent) scorePoints += 1;
if (hasClearService) scorePoints += 1;
if (hasColdIntent) scorePoints -= 3;
if (missingFields.length > 0) scorePoints -= 4;

// Determine urgency level.
// The selected form urgency is prioritized first.
let urgencyLevel = 'Low';

if (selectedUrgency.includes('high')) {
  urgencyLevel = 'High';
} else if (selectedUrgency.includes('medium')) {
  urgencyLevel = 'Medium';
} else if (selectedUrgency.includes('low')) {
  urgencyLevel = 'Low';
} else if (hasUrgentIntent) {
  urgencyLevel = 'High';
} else if (hasWarmIntent || schedule) {
  urgencyLevel = 'Medium';
}

// Determine lead score.
// Final rules:
// 1. Missing required info = Needs Manual Review
// 2. High urgency + cold/unclear intent = Warm, not Cold
// 3. Low/Medium urgency + cold intent = Cold
// 4. High urgency + strong complete details = Hot
// 5. Medium/Low urgency + complete enough details = Warm
// 6. Weak or vague lead = Cold

let leadScore = 'Cold';

if (missingFields.length > 0) {
  leadScore = 'Needs Manual Review';
} else if (hasColdIntent && urgencyLevel === 'High') {
  leadScore = 'Warm';
} else if (hasColdIntent && urgencyLevel !== 'High') {
  leadScore = 'Cold';
} else if (urgencyLevel === 'High' && scorePoints >= 7 && hasStrongLeadInfo) {
  leadScore = 'Hot';
} else if (urgencyLevel === 'Medium' && scorePoints >= 5) {
  leadScore = 'Warm';
} else if (urgencyLevel === 'Low' && scorePoints >= 5) {
  leadScore = 'Warm';
} else {
  leadScore = 'Cold';
}

const leadSummary = `${fullName || 'A new lead'} requested ${service || 'a cleaning service'}${propertyType ? ' for a ' + propertyType : ''}${location ? ' in ' + location : ''}${schedule ? ' with preferred schedule: ' + schedule : ''}.`;

const actions = {
  Hot: 'Send booking link immediately, notify the owner, and follow up within 1 business hour.',
  Warm: 'Ask one qualifying question, provide service information, and follow up within 24 hours.',
  Cold: 'Send a polite reply and keep the lead in the nurture list.',
  'Needs Manual Review': 'Review missing lead details manually before sending a final quote or booking link.'
};

const bookingStatus =
  leadScore === 'Hot'
    ? 'Booking Link Sent'
    : leadScore === 'Warm'
      ? 'Needs Follow-Up'
      : leadScore === 'Cold'
        ? 'Nurture'
        : 'Manual Review';

const followUpStatus =
  leadScore === 'Hot'
    ? 'Follow up after booking link'
    : leadScore === 'Warm'
      ? 'Ask qualifying question'
      : leadScore === 'Cold'
        ? 'Low priority nurture'
        : 'Check missing information';

const crmStage =
  leadScore === 'Hot'
    ? 'Appointment Booking'
    : leadScore === 'Warm'
      ? 'AI Qualified'
      : leadScore === 'Cold'
        ? 'Nurture'
        : 'New Lead - Manual Review';

const taskStatus =
  leadScore === 'Hot'
    ? 'High Priority'
    : leadScore === 'Warm'
      ? 'Needs Follow-Up'
      : leadScore === 'Cold'
        ? 'Low Priority'
        : 'Manual Review';

const followUpPriority =
  leadScore === 'Hot'
    ? 'High'
    : leadScore === 'Warm'
      ? 'Medium'
      : leadScore === 'Needs Manual Review'
        ? 'High'
        : 'Low';

const nextFollowUpHours =
  leadScore === 'Hot'
    ? 2
    : leadScore === 'Warm'
      ? 24
      : leadScore === 'Needs Manual Review'
        ? 4
        : 72;

const nextFollowUp = new Date(Date.now() + nextFollowUpHours * 60 * 60 * 1000).toISOString();
const dateSubmitted = new Date().toISOString();

const calendarBookingLink = lead.calendar_booking_link || 'https://calendar.google.com';

const emailTemplates = {
  Hot: {
    subject: 'Book Your Cleaning Service Appointment',
    body: `Hi ${firstName},

Thank you for reaching out to CleanPro.

We received your request for ${service || 'cleaning service'}${location ? ' in ' + location : ''}. Based on your preferred schedule, your request looks time-sensitive, so you can book your cleaning appointment here:

${calendarBookingLink}

After you choose a time, our team will review your details and confirm the appointment.

Best,
CleanPro Team`
  },

  Warm: {
    subject: 'Quick Question About Your Cleaning Request',
    body: `Hi ${firstName},

Thank you for contacting CleanPro.

We received your request for ${service || 'cleaning service'}${location ? ' in ' + location : ''}. To recommend the best cleaning option, could you please confirm your preferred cleaning date and approximate property size?

Once we have those details, we can help you choose the right service.

Best,
CleanPro Team`
  },

  Cold: {
    subject: 'Thanks for Contacting CleanPro',
    body: `Hi ${firstName},

Thank you for reaching out to CleanPro.

We received your cleaning service inquiry. When you are ready, you can reply to this email with more details about your preferred schedule, property type, and cleaning needs.

We’ll be happy to help.

Best,
CleanPro Team`
  },

  'Needs Manual Review': {
    subject: 'We Received Your Cleaning Request',
    body: `Hi ${firstName},

Thank you for contacting CleanPro.

We received your inquiry, but our team needs to review a few details before sending the best next step. We will check your request and follow up shortly.

Best,
CleanPro Team`
  }
};

let hasBookableSchedule = false;
let calendarStart = '';
let calendarEnd = '';
let preferredScheduleDisplay = schedule;

// Default timezone for the demo business/location. Davao City uses Philippine Time.
// Change this offset if your cleaning business uses another timezone.
const calendarTimeZoneOffset = '+08:00';
const calendarTimeZone = 'Asia/Manila';

function pad2(value) {
  return String(value).padStart(2, '0');
}

function offsetToMinutes(offset) {
  const match = String(offset).match(/^([+-])(\d{2}):(\d{2})$/);
  if (!match) return 0;
  const sign = match[1] === '-' ? -1 : 1;
  return sign * (Number(match[2]) * 60 + Number(match[3]));
}

function formatDateInOffset(date, offset) {
  const offsetMinutes = offsetToMinutes(offset);
  const shifted = new Date(date.getTime() + offsetMinutes * 60 * 1000);
  return shifted.toISOString().slice(0, 19) + offset;
}

function formatScheduleDisplay(year, month, day, hour24, minute) {
  const suffix = hour24 >= 12 ? 'PM' : 'AM';
  const hour12 = hour24 % 12 || 12;
  return `${year}-${month}-${day} ${hour12}:${minute} ${suffix}`;
}

function parsePreferredScheduleToCalendar(scheduleValue) {
  const value = clean(scheduleValue);
  if (!value) return null;

  // Accepts HTML datetime-local values such as 2026-06-28T10:00
  // and typed values such as 2026-06-28 10:00 AM.
  const exactDateTime = value.match(/^(\d{4})-(\d{2})-(\d{2})[T\s](\d{1,2}):(\d{2})(?::(\d{2}))?\s*([AaPp][Mm])?$/);

  if (exactDateTime) {
    const year = exactDateTime[1];
    const month = exactDateTime[2];
    const day = exactDateTime[3];
    let hour = Number(exactDateTime[4]);
    const minute = exactDateTime[5];
    const second = exactDateTime[6] || '00';
    const ampm = exactDateTime[7] ? exactDateTime[7].toLowerCase() : '';

    if (ampm === 'pm' && hour < 12) hour += 12;
    if (ampm === 'am' && hour === 12) hour = 0;

    if (hour < 0 || hour > 23) return null;

    const start = `${year}-${month}-${day}T${pad2(hour)}:${minute}:${second}${calendarTimeZoneOffset}`;
    const startDate = new Date(Date.parse(start));
    const endDate = new Date(startDate.getTime() + 30 * 60 * 1000);

    return {
      start,
      end: formatDateInOffset(endDate, calendarTimeZoneOffset),
      display: formatScheduleDisplay(year, month, day, hour, minute)
    };
  }

  // Fallback for other parseable natural dates, for example: June 28, 2026 10:00 AM.
  const parsedDate = Date.parse(value);
  if (!Number.isNaN(parsedDate)) {
    const startDate = new Date(parsedDate);
    const endDate = new Date(startDate.getTime() + 30 * 60 * 1000);
    return {
      start: startDate.toISOString(),
      end: endDate.toISOString(),
      display: value
    };
  }

  return null;
}

const parsedSchedule = parsePreferredScheduleToCalendar(schedule);

if (parsedSchedule) {
  calendarStart = parsedSchedule.start;
  calendarEnd = parsedSchedule.end;
  preferredScheduleDisplay = parsedSchedule.display;
  hasBookableSchedule = true;
}

let scoringExplanation = '';

if (leadScore === 'Hot') {
  scoringExplanation = 'Lead is urgent, complete, and appears ready to book.';
} else if (leadScore === 'Warm') {
  scoringExplanation = hasColdIntent && urgencyLevel === 'High'
    ? 'Lead selected high urgency but contains unclear or price-shopping language, so it needs follow-up before booking.'
    : 'Lead has enough information but needs follow-up before booking.';
} else if (leadScore === 'Cold') {
  scoringExplanation = hasColdIntent
    ? 'Lead contains low-intent or price-shopping language such as maybe, later, cheapest, or just checking.'
    : 'Lead does not show enough urgency or buying intent yet.';
} else {
  scoringExplanation = `Lead is missing required fields: ${missingFields.join(', ')}.`;
}

return [
  {
    json: {
      ...lead,

      first_name: firstName,
      date_submitted: dateSubmitted,

      lead_score: leadScore,
      urgency_level: urgencyLevel,
      lead_summary: leadSummary,
      recommended_next_action: actions[leadScore],
      follow_up_priority: followUpPriority,

      reason_for_score: `Rule-based score: ${scorePoints}. ${scoringExplanation} Selected urgency: ${urgency || 'Not provided'}. Final urgency level: ${urgencyLevel}. Cold intent detected: ${hasColdIntent ? 'Yes' : 'No'}. Missing required fields: ${missingFields.length ? missingFields.join(', ') : 'None'}.`,

      suggested_reply: emailTemplates[leadScore].body,
      email_subject: emailTemplates[leadScore].subject,
      email_body: emailTemplates[leadScore].body,

      booking_status: bookingStatus,
      follow_up_status: followUpStatus,
      crm_stage: crmStage,
      task_status: taskStatus,
      next_follow_up: nextFollowUp,
      last_activity: 'New lead captured and scored by free n8n rules engine',

      missing_required_fields: missingFields.join(', '),
      preferred_schedule_display: preferredScheduleDisplay,
      calendar_timezone: calendarTimeZone,

      has_bookable_schedule: hasBookableSchedule,
      calendar_start: calendarStart,
      calendar_end: calendarEnd
    }
  }
];
